import 'package:flutter/material.dart'; import 'package:shared_preferences/shared_preferences.dart'; class SettingsScreen extends StatefulWidget { const SettingsScreen({super.key}); @override State<SettingsScreen> createState() => _SettingsScreenState(); } class _SettingsScreenState extends State<SettingsScreen> { bool _dark = true; @override void initState() { super.initState(); _load(); } Future<void> _load() async { final p = await SharedPreferences.getInstance(); setState(()=>_dark = p.getBool('darkMode')??true); } Future<void> _setDark(bool v) async { final p = await SharedPreferences.getInstance(); await p.setBool('darkMode', v); setState(()=>_dark = v); } @override Widget build(BuildContext context) => Scaffold(appBar: AppBar(title: const Text('الإعدادات')), body: ListView(children: [ SwitchListTile(title: const Text('الوضع الليلي'), value: _dark, onChanged: _setDark), ListTile(leading: const Icon(Icons.sync), title: const Text('مزامنة الآن'), onTap: ()=>ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('جاري المزامنة...')))) ])); }
